#include<bits/stdc++.h>
using namespace std;

int main(){
    int a,b,ans=0;
    cin>>a>>b;
    for(int i=a;i<=b;i++){
        long long x=i,old,now;
        cin>>x;
        while(x){
            old=x/10%10,now=x%10;
            if(now<=old){
                ans--;
                break;
            }
            x/=10;
        }
        ans++;
    }
    cout<<ans;
    return 0;
}
